// ── Toast ─────────────────────────────────────────────────────────────────────
function Toast({ msg, type, onClose }) {
  useEffect(() => { const t = setTimeout(onClose, 4000); return () => clearTimeout(t); }, [onClose]);
  const bg = type==="error" ? "#b33a3a" : C.primary;
  return (
    <div style={{ position:"fixed", bottom:24, right:24, zIndex:9999, background:bg, color:"#fff", padding:"14px 20px", borderRadius:10, boxShadow:"0 4px 20px rgba(0,0,0,0.15)", fontWeight:600, fontSize:14, maxWidth:300, display:"flex", alignItems:"center", gap:10 }}>
      <span style={{ flex:1 }}>{msg}</span>
      <button onClick={onClose} style={{ background:"none", border:"none", color:"#fff", cursor:"pointer", fontSize:20 }}>×</button>
    </div>
  );
}

// ── Star Rating Widget (standalone, no bugs) ──────────────────────────────────
function StarRating({ value, onChange }) {
  const [hovered, setHovered] = useState(0);
  const labels = ["","Poor","Fair","Good","Great","Excellent"];
  const colors = ["","#e74c3c","#e67e22","#f1c40f","#2ecc71",C.primary];
  const active = hovered || value;
  return (
    <div style={{ display:"flex", alignItems:"center", gap:6 }}>
      {[1,2,3,4,5].map(n => (
        <button
          key={n}
          type="button"
          onMouseEnter={() => setHovered(n)}
          onMouseLeave={() => setHovered(0)}
          onClick={() => onChange(n)}
          style={{
            width:38, height:38, borderRadius:8, border:"none", cursor:"pointer",
            fontSize:20, fontWeight:700, lineHeight:1,
            background: n <= active ? colors[active] : C.light,
            color:      n <= active ? "#fff" : C.muted,
            transition:"all .12s",
          }}
        >★</button>
      ))}
      {active > 0 && (
        <span style={{ color:colors[active], fontSize:13, fontWeight:600, marginLeft:4 }}>
          {labels[active]}
        </span>
      )}
    </div>
  );
}

// ── Reviews Section ───────────────────────────────────────────────────────────
function ReviewsSection({ reviews, setReviews, showToast }) {
  const blank = { name:"", goal:"", rating:0, text:"" };
  const [form, setForm]     = useState(blank);
  const [errors, setErrors] = useState({});
  const [done, setDone]     = useState(false);
  const goals = [...SERVICES.map(s=>s.title), "General Consultation"];
  const colors = ["","#e74c3c","#e67e22","#f1c40f","#2ecc71",C.primary];

  const validate = () => {
    const e = {};
    if (!form.name.trim())           e.name   = "Enter your name";
    if (!form.goal)                  e.goal   = "Select your diet plan";
    if (form.rating === 0)           e.rating = "Please select a rating";
    if (form.text.trim().length < 10) e.text  = "Write at least 10 characters";
    setErrors(e);
    return Object.keys(e).length === 0;
  };

  const submit = () => {
    if (!validate()) return;
    setReviews(prev => [{
      id:     Date.now(),
      name:   form.name.trim(),
      goal:   form.goal,
      rating: form.rating,
      text:   form.text.trim(),
      date:   new Date().toLocaleDateString("en-IN", { day:"numeric", month:"short", year:"numeric" }),
      avatar: form.name.trim()[0].toUpperCase(),
    }, ...prev]);
    setForm(blank);
    setErrors({});
    setDone(true);
    showToast("Thank you for your feedback! 🌿");
    setTimeout(() => setDone(false), 3500);
  };

  const inp = (k) => ({
    width:"100%", padding:"10px 13px", borderRadius:8, fontSize:14,
    outline:"none", boxSizing:"border-box", fontFamily:"inherit",
    border: errors[k] ? `1.5px solid ${C.red}` : `1.5px solid ${C.border}`,
    background: C.surface,
  });

  return (
    <section style={{ padding:"70px 20px", background:C.warm, borderTop:`1px solid ${C.border}`, borderBottom:`1px solid ${C.border}` }}>
      <div style={{ maxWidth:980, margin:"0 auto" }}>
        <div style={{ textAlign:"center", marginBottom:44 }}>
          <div style={{ color:C.accent, fontWeight:700, letterSpacing:2, fontSize:12, marginBottom:8 }}>CLIENT FEEDBACK</div>
          <h2 style={{ fontFamily:"Georgia,serif", fontSize:"clamp(1.5rem,3vw,2.2rem)", color:C.text, margin:0 }}>What Our Clients Say</h2>
          <div style={{ width:50, height:3, background:C.gold, margin:"14px auto 0", borderRadius:2 }}/>
        </div>
        <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fit,minmax(300px,1fr))", gap:30, alignItems:"start" }}>
          {/* Submit Form */}
          <div style={{ background:C.surface, borderRadius:16, padding:"28px 24px", border:`1px solid ${C.border}`, boxShadow:"0 3px 16px rgba(46,125,82,0.08)" }}>
            <h3 style={{ color:C.text, fontFamily:"Georgia,serif", margin:"0 0 6px", fontSize:19 }}>Share Your Experience</h3>
            <p style={{ color:C.muted, fontSize:13, marginBottom:20 }}>Had a consultation? Let others know how it went.</p>
            <div style={{ marginBottom:14 }}>
              <label style={{ fontSize:13, fontWeight:600, color:C.text, display:"block", marginBottom:6 }}>Your Name *</label>
              <input value={form.name} onChange={e => setForm(p=>({...p,name:e.target.value}))} style={inp("name")} placeholder="e.g. Priya S."/>
              {errors.name && <div style={{ color:C.red, fontSize:12, marginTop:4 }}>{errors.name}</div>}
            </div>
            <div style={{ marginBottom:14 }}>
              <label style={{ fontSize:13, fontWeight:600, color:C.text, display:"block", marginBottom:6 }}>Diet Plan *</label>
              <select value={form.goal} onChange={e => setForm(p=>({...p,goal:e.target.value}))} style={inp("goal")}>
                <option value="">Select your plan</option>
                {goals.map(g => <option key={g}>{g}</option>)}
              </select>
              {errors.goal && <div style={{ color:C.red, fontSize:12, marginTop:4 }}>{errors.goal}</div>}
            </div>
            <div style={{ marginBottom:14 }}>
              <label style={{ fontSize:13, fontWeight:600, color:C.text, display:"block", marginBottom:8 }}>Rating *</label>
              <StarRating value={form.rating} onChange={v => setForm(p=>({...p,rating:v}))} />
              {errors.rating && <div style={{ color:C.red, fontSize:12, marginTop:6 }}>{errors.rating}</div>}
            </div>
            <div style={{ marginBottom:20 }}>
              <label style={{ fontSize:13, fontWeight:600, color:C.text, display:"block", marginBottom:6 }}>Your Feedback *</label>
              <textarea value={form.text} onChange={e => setForm(p=>({...p,text:e.target.value}))} rows={4} placeholder="Tell us about your experience and results..." style={{ ...inp("text"), resize:"vertical", lineHeight:1.6 }}/>
              {errors.text && <div style={{ color:C.red, fontSize:12, marginTop:4 }}>{errors.text}</div>}
            </div>
            {done
              ? <div style={{ background:C.light, border:`1px solid ${C.border}`, color:C.primary, padding:"12px", borderRadius:8, textAlign:"center", fontWeight:600 }}>✅ Review posted! Thank you.</div>
              : <button onClick={submit} style={{ width:"100%", background:C.primary, border:"none", color:"#fff", padding:"12px", borderRadius:8, fontSize:15, fontWeight:700, cursor:"pointer" }}>Submit Feedback →</button>
            }
          </div>

          {/* Reviews Display */}
          <div style={{ display:"flex", flexDirection:"column", gap:14, maxHeight:520, overflowY:"auto" }}>
            {reviews.length === 0
              ? (
                <div style={{ background:C.surface, borderRadius:14, padding:"52px 24px", textAlign:"center", border:`1px dashed ${C.border}` }}>
                  <div style={{ fontSize:44, marginBottom:14 }}>💬</div>
                  <div style={{ color:C.text, fontWeight:600, fontSize:16, marginBottom:8 }}>No reviews yet</div>
                  <div style={{ color:C.muted, fontSize:14, lineHeight:1.7 }}>Be the first to share your experience with Dietician Madhu Mitha.</div>
                </div>
              )
              : reviews.map(r => (
                <div key={r.id} style={{ background:C.surface, borderRadius:14, padding:"18px 20px", border:`1px solid ${C.border}`, boxShadow:"0 2px 10px rgba(46,125,82,0.06)" }}>
                  <div style={{ display:"flex", justifyContent:"space-between", marginBottom:10 }}>
                    <div style={{ display:"flex", alignItems:"center", gap:12 }}>
                      <div style={{ width:40, height:40, borderRadius:"50%", background:C.light, color:C.primary, display:"flex", alignItems:"center", justifyContent:"center", fontWeight:700, fontSize:17, border:`2px solid ${C.border}`, flexShrink:0 }}>{r.avatar}</div>
                      <div>
                        <div style={{ fontWeight:700, color:C.text }}>{r.name}</div>
                        <div style={{ color:C.accent, fontSize:12, fontWeight:600 }}>{r.goal}</div>
                      </div>
                    </div>
                    <div style={{ textAlign:"right" }}>
                      <div style={{ color:colors[r.rating], fontSize:15 }}>{"★".repeat(r.rating)}{"☆".repeat(5-r.rating)}</div>
                      <div style={{ color:"#bbb", fontSize:11, marginTop:2 }}>{r.date}</div>
                    </div>
                  </div>
                  <p style={{ color:C.muted, fontSize:14, lineHeight:1.8, margin:0, fontStyle:"italic" }}>"{r.text}"</p>
                </div>
              ))
            }
          </div>
        </div>
      </div>
    </section>
  );
}

