// ── User Login — standalone ───────────────────────────────────────────────────
function UserAuthPage({ setCurrentUser, navigate, showToast }) {
  const [mode, setMode]   = useState("login");
  const [form, setForm]   = useState({ userId:"", name:"", email:"", phone:"", password:"" });
  const [showPw, setShowPw] = useState(false);
  const [err,  setErr]    = useState("");
  const [users, setUsers] = useState(DEMO_USERS);

  const up = (k,v) => { setForm(p=>({...p,[k]:v})); setErr(""); };

  const handle = () => {
    if (mode==="login") {
      const u = users.find(u => u.userId===form.userId.trim() && u.password===form.password);
      if (u) { setCurrentUser({ ...u, appointments:[] }); showToast(`Welcome, ${u.name}!`); navigate("userDash"); }
      else setErr("Incorrect User ID or password.");
    } else {
      if (!form.userId.trim()||!form.name.trim()||!form.email.trim()||!form.phone.trim()||!form.password) { setErr("All fields are required."); return; }
      if (users.find(u=>u.userId===form.userId.trim())) { setErr("User ID already taken."); return; }
      const u = { userId:form.userId.trim(), name:form.name.trim(), email:form.email.trim(), phone:form.phone.trim(), password:form.password, appointments:[] };
      setUsers(p=>[...p,u]); setCurrentUser(u); showToast(`Account created! Welcome, ${u.name}!`); navigate("userDash");
    }
  };

  const s = { width:"100%", padding:"11px 14px", borderRadius:8, border:`1.5px solid ${C.border}`, fontSize:14, boxSizing:"border-box", background:C.surface, outline:"none" };
  const lbl = { fontSize:13, fontWeight:600, color:C.text, display:"block", marginBottom:6 };

  return (
    <div style={{ background:C.bg, minHeight:"100vh", display:"flex", alignItems:"center", justifyContent:"center", padding:20 }}>
      <div style={{ background:C.surface, borderRadius:16, padding:"40px 34px", maxWidth:420, width:"100%", boxShadow:"0 4px 24px rgba(46,125,82,0.10)", border:`1px solid ${C.border}` }}>
        <div style={{ textAlign:"center", marginBottom:22 }}><Logo size={52}/></div>
        <h2 style={{ fontFamily:"Georgia,serif", color:C.text, textAlign:"center", margin:"0 0 6px" }}>{mode==="login"?"Welcome Back":"Create Account"}</h2>
        <p style={{ color:C.muted, textAlign:"center", fontSize:13, marginBottom:24 }}>{mode==="login"?"Login to view your appointments":"Register to book your first consultation"}</p>

        {/* Tabs */}
        <div style={{ display:"flex", marginBottom:24, border:`1px solid ${C.border}`, borderRadius:8, overflow:"hidden" }}>
          {[["login","Login"],["register","Register"]].map(([m,l])=>(
            <button key={m} onClick={()=>{ setMode(m); setErr(""); setForm({ userId:"", name:"", email:"", phone:"", password:"" }); }}
              style={{ flex:1, padding:"10px", border:"none", background:mode===m?C.primary:C.surface, color:mode===m?"#fff":C.muted, fontWeight:mode===m?700:400, cursor:"pointer", fontSize:14 }}>
              {l}
            </button>
          ))}
        </div>

        <div style={{ marginBottom:14 }}>
          <label style={lbl}>User ID *</label>
          <input value={form.userId} onChange={e=>up("userId",e.target.value)} onKeyDown={e=>e.key==="Enter"&&handle()} style={s} placeholder="Your unique user ID"/>
        </div>
        {mode==="register" && <>
          <div style={{ marginBottom:14 }}><label style={lbl}>Full Name *</label><input value={form.name} onChange={e=>up("name",e.target.value)} style={s} placeholder="Your full name"/></div>
          <div style={{ marginBottom:14 }}><label style={lbl}>Email *</label><input type="email" value={form.email} onChange={e=>up("email",e.target.value)} style={s} placeholder="you@email.com"/></div>
          <div style={{ marginBottom:14 }}><label style={lbl}>Phone *</label><input value={form.phone} onChange={e=>up("phone",e.target.value)} style={s} placeholder="10-digit mobile"/></div>
        </>}
        <div style={{ marginBottom:20, position:"relative" }}>
          <label style={lbl}>Password *</label>
          <input type={showPw?"text":"password"} value={form.password} onChange={e=>up("password",e.target.value)} onKeyDown={e=>e.key==="Enter"&&handle()} style={s} placeholder="Password"/>
          <button type="button" onClick={()=>setShowPw(p=>!p)} style={{ position:"absolute", right:12, top:34, background:"none", border:"none", color:C.muted, cursor:"pointer", fontSize:14 }}>{showPw?"🙈":"👁"}</button>
        </div>

        {err && <div style={{ background:"#fdecea", color:C.red, padding:"10px 14px", borderRadius:8, marginBottom:14, fontSize:13 }}>⚠️ {err}</div>}
        <button onClick={handle} style={{ width:"100%", background:C.primary, border:"none", color:"#fff", padding:"13px", borderRadius:8, fontSize:16, fontWeight:700, cursor:"pointer" }}>{mode==="login"?"Login →":"Create Account →"}</button>

        <button onClick={()=>navigate("booking")} style={{ display:"block", margin:"14px auto 0", background:"none", border:"none", color:C.gold, cursor:"pointer", fontWeight:600, fontSize:14 }}>Continue as guest →</button>

        {mode==="login" && (
          <div style={{ marginTop:16, background:C.light, borderRadius:8, padding:"9px 13px", fontSize:12, color:C.primary, border:`1px solid ${C.border}` }}>
            Demo — User ID: <strong>prithick</strong> / Password: <strong>user123</strong>
          </div>
        )}
      </div>
    </div>
  );
}

